INSERT INTO profiles (id, name, title, bio, avatar, roles, member_since, location, verified, verification_level, verification_email, verification_identity, verification_track_record, followers, trust_score, fulfillment_rate, update_consistency, repeat_donor_confidence, campaigns_organized, campaigns_funded, total_raised, total_donated, recommended_by) VALUES ('profile-1', 'Maya Chen', 'Community Architect & Urban Farmer', 'Maya has spent the last decade transforming vacant lots and neglected rooftops into productive green spaces across Portland. She holds a Master''s in Urban Planning from Portland State and previously managed the city''s Office of Community Gardens. Her campaigns consistently exceed their goals because she treats every backer like a neighbor, not a transaction.', '/images/avatar-maya.jpg', '["organizer","donor"]', '2023-03-15', 'Portland, OR', 1, 'track_record', 1, 1, 1, 3842, 93, 100, 91, 85, 8, 6, 354200, 4850, 47);
INSERT INTO profiles (id, name, title, bio, avatar, roles, member_since, location, verified, verification_level, verification_email, verification_identity, verification_track_record, followers, trust_score, fulfillment_rate, update_consistency, repeat_donor_confidence, campaigns_organized, campaigns_funded, total_raised, total_donated, recommended_by) VALUES ('profile-2', 'Jonas Reid', 'Sustainability Engineer & Maker', 'Jonas left a senior role at an energy consultancy to focus on grassroots infrastructure projects in Austin. He''s an electrical engineer by training who believes the fastest path to equitable energy access is neighbor-to-neighbor cooperation. When he''s not wiring solar panels, he mentors first-time campaign organizers through the FundForge community program.', '/images/avatar-jonas.jpg', '["organizer","donor","mentor"]', '2022-08-20', 'Austin, TX', 1, 'track_record', 1, 1, 1, 5120, 89, 100, 85, 78, 6, 4, 375000, 12200, 62);
INSERT INTO profiles (id, name, title, bio, avatar, roles, member_since, location, verified, verification_level, verification_email, verification_identity, verification_track_record, followers, trust_score, fulfillment_rate, update_consistency, repeat_donor_confidence, campaigns_organized, campaigns_funded, total_raised, total_donated, recommended_by) VALUES ('profile-3', 'Elena Ortiz', 'Environmental Scientist & Watershed Advocate', 'Elena is a water quality researcher at UC Riverside who channels her fieldwork into direct community action. She launched her first campaign after discovering unsafe lead levels in the Riverside District''s aging infrastructure. Four of her five completed campaigns have exceeded their funding goals.', '/images/avatar-elena.jpg', '["organizer"]', '2023-11-01', 'Riverside, CA', 1, 'identity', 1, 1, 0, 1876, 84, 80, 90, 82, 6, 4, 184600, 1500, 28);
INSERT INTO profiles (id, name, title, bio, avatar, roles, member_since, location, verified, verification_level, verification_email, verification_identity, verification_track_record, followers, trust_score, fulfillment_rate, update_consistency, repeat_donor_confidence, campaigns_organized, campaigns_funded, total_raised, total_donated, recommended_by) VALUES ('profile-4', 'Samir Patel', 'Tech Educator & Digital Equity Advocate', 'Samir spent eight years teaching computer science at Chicago public schools before realizing the biggest barrier wasn''t curriculum but access. His campaigns focus on closing the digital divide through community WiFi, device drives, and hands-on tutoring centers. Three of his four completed campaigns have hit their goals.', '/images/avatar-samir.jpg', '["organizer","donor"]', '2024-01-10', 'Chicago, IL', 1, 'identity', 1, 1, 0, 982, 77, 75, 82, 76, 6, 3, 174800, 3200, 15);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-1', 'profile-1', 'Grow a Rooftop Garden for 400 Neighborhood Families', 'Urban Agriculture', 'active', '/images/hero-garden.jpg', '["/images/campaign-detail.jpg"]', 120000, '{"amount":160000,"label":"Add composting facility + second greenhouse"}', NULL, 86400, 1168, 74, '2026-01-15', '2026-03-19', NULL, 12, 22, '["Three years ago, the roof of the old Eastside Cannery was a gravel wasteland. Pigeons roosted in the stairwell, and the only things growing were weeds pushing through cracks in the parapet. Today that same roof holds 2,400 square feet of raised beds, a rainwater collection system, and a small greenhouse that extends the growing season by eight weeks. Over 120 families harvest from it every month.","This campaign is about doing it again, bigger, on the warehouse at 14th and Division.","The Division Street warehouse sits on the border of four census tracts. Three of them qualify as USDA food deserts, meaning residents travel more than a mile to reach a full-service grocery store. The nearest farmers market runs only on Saturday mornings, June through September. For the 400 families within walking distance of this building, fresh produce is a car trip, a bus transfer, or a luxury.","We have a signed lease with the building owner, Renata Vasquez, who has agreed to a 10-year community use agreement at $1 per year. The structural engineer''s report confirms the roof can support 22 inches of growing medium across 4,800 square feet. The city''s Bureau of Environmental Services has pre-approved our stormwater management plan, which routes overflow into a bioswale on the south side of the building.","Here is what the money covers. The first $45,000 goes to structural reinforcement and waterproof membrane installation. This is the unsexy part, and it is the most important. A roof garden that leaks is a lawsuit, not a community asset. We are working with Greenroof Systems NW, the same contractor who built the Eastside Cannery installation. They warranty their membrane work for 25 years.","The next $35,000 covers soil, beds, irrigation, and the greenhouse kit. We are using a modular raised bed system from a local fabricator, welded from recycled steel. Each bed is 4 feet by 12 feet and holds 18 inches of custom growing medium. The drip irrigation system runs off the rainwater cisterns, with municipal backup for dry spells. The greenhouse is a 12-by-20 polycarbonate kit that we will assemble with volunteer labor.","The remaining $40,000 funds the first two years of operation: a part-time garden manager, seeds and starts, tool maintenance, composting infrastructure, and community education programming. We run monthly workshops on container gardening, food preservation, and nutrition. Last year at the Cannery garden, 83% of workshop attendees reported eating more vegetables at home within three months.","We are not building a demonstration project. We are building food infrastructure that outlasts any single grant cycle. The lease runs through 2036. The raised beds last 15 years. The membrane lasts 25. Every dollar you contribute buys something that will still be feeding families when the kids in this neighborhood are graduating high school.","If you have been to the Cannery garden, you know what this looks like when it works. If you have not, come by on a Tuesday evening. The beds are full of kale and chard right now, and someone usually brings coffee."]', '[{"id":"update-1-1","date":"2026-03-05","title":"Construction Starts Next Week","content":"The membrane crew from Greenroof Systems NW is scheduled to begin on March 12. We finalized the waterproofing spec last week and ordered materials. Weather looks clear through the 20th.","image":"/images/campaign-detail.jpg"},{"id":"update-1-2","date":"2026-02-20","title":"We Passed 70% - Thank You","content":"86 new backers joined this week alone. We also received a $5,000 match from the Portland Community Foundation, which is reflected in the current total. The structural reinforcement phase is fully funded."},{"id":"update-1-3","date":"2026-02-01","title":"Site Assessment Complete","content":"The engineer''s report came back clean. Roof load capacity exceeds our requirements by 30%. We also confirmed the rainwater cistern placement with the Bureau of Environmental Services."},{"id":"update-1-4","date":"2026-01-20","title":"Campaign Launch - Here We Go","content":"After six months of planning, permits, and lease negotiations, we are live. Thank you to the 142 people who backed us in the first 48 hours. That early momentum matters more than you know."}]', '[{"donorName":"Ari Lewis","text":"I backed Maya''s Cannery garden two years ago and watched my neighbors start cooking with fresh greens for the first time. She does what she says she''ll do.","date":"2026-02-18"},{"donorName":"Rachel Kim","text":"The weekly updates alone are worth it. You always know exactly where the money is going and what''s happening on site.","date":"2026-02-25"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-2', 'profile-2', 'Neighborhood Solar Co-op: Clean Energy for 200 Homes', 'Renewable Energy', 'active', '/images/hero-solar.jpg', '["/images/campaign-detail.jpg"]', 200000, '{"amount":280000,"label":"Expand to 100 additional homes in Westside"}', NULL, 162800, 1892, 86, '2025-12-01', '2026-03-30', NULL, 23, 18, '["The average electricity bill in the Eastside neighborhood of Austin hit $287 last July. For a household earning $42,000 a year, that is 8% of gross income going to keep the lights on and the AC running. Meanwhile, Austin Energy''s residential solar rebate program has a two-year waitlist, and most private installers require a credit score above 680 to finance a system.","We are building a solar cooperative that bypasses both problems.","The model is straightforward. We pool funds from this campaign with a low-interest loan from the Austin Community Development Corporation to purchase solar panel systems in bulk. Bulk purchasing drops the per-watt cost from $2.80 to $1.95, a 30% savings. Each participating household gets a 5kW rooftop system installed by licensed electricians from IBEW Local 520, and pays back the cost through their energy savings over seven years. After that, the electricity is theirs, free.","We have already signed agreements with 147 households. The remaining 53 slots will fill from our waitlist once this campaign closes. Every home has been assessed for roof condition, shading, and electrical panel capacity. Forty-two homes needed panel upgrades, which are included in the project budget.","The numbers work like this. A 5kW system in Austin generates roughly 7,000 kWh per year. At Austin Energy''s current residential rate of $0.11 per kWh, that is $770 in annual savings per household. Over the seven-year payback period, each household saves a net $1,390 after covering their share of installation costs. After year seven, they save $770 annually for the remaining 18-year warranty life of the panels. Total lifetime savings per home: over $15,000.","For the 200 homes combined, that is $3 million in energy savings over the system lifetime and 2,800 metric tons of avoided CO2 emissions. We worked those numbers with Austin Energy''s own calculator and had them verified by an independent energy auditor.","The $200,000 goal covers the gap between our bulk purchase price and the ACDC loan. Specifically: $120,000 for the 42 electrical panel upgrades that the loan does not cover, $45,000 for permitting and interconnection fees across 200 installations, $20,000 for project management and quality assurance over the 8-month installation timeline, and $15,000 for a reserve fund to cover warranty claims in the first two years.","This is my fifth community infrastructure campaign. The previous four all delivered on time and on budget. I post updates every week during active projects. You can read the full post-project reports for the Youth Coding Workshop, the River Walk murals, the Community Greenhouse, and the Makers Space on my profile page.","Every household in the co-op signs a simple participation agreement. They grant roof access for installation and maintenance, agree to the seven-year payback schedule deducted from their energy savings, and commit to keeping trees trimmed away from the panels. In exchange, they own their system outright after year seven. No liens, no financing companies, no credit checks. The co-op structure means neighbors hold each other accountable, and it means the project scales. If this works for 200 homes in Eastside, there is no reason it cannot work for 2,000 homes across Austin.","If 200 homes generating their own clean electricity sounds ambitious, it is. But the engineering is proven, the financing structure works, and the families are ready. We just need to close the funding gap."]', '[{"id":"update-2-1","date":"2026-03-03","title":"First 50 Homes Have Panels on the Roof","content":"Installation crews completed the southeast cluster ahead of schedule. All 50 systems passed city inspection on the first try. We are seeing 15-20% higher output than projected thanks to the unusually clear February.","image":"/images/hero-campaign.jpg"},{"id":"update-2-2","date":"2026-02-15","title":"Panel Installation Underway","content":"IBEW Local 520 crews started on February 10. We are running two crews of four, each completing 3-4 installations per day. The bulk panel shipment from Q Cells arrived without damage."},{"id":"update-2-3","date":"2026-01-28","title":"All Permits Approved","content":"200 residential solar permits approved by the City of Austin. This is the largest single batch they have processed. We also locked in our interconnection agreements with Austin Energy."}]', '[{"donorName":"Lisa Chang","text":"Jonas ran the Community Greenhouse campaign two years ago. Everything he promised was delivered, on time, documented. I trust his project management completely.","date":"2026-02-10"},{"donorName":"Chris Walker","text":"My family is one of the 200 households. Our July electric bill was $312. This project changes our monthly budget in a real way.","date":"2026-01-15"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-3', 'profile-3', 'Clean Water Commons: Filtration for Riverside District', 'Environmental', 'active', '/images/hero-water.jpg', '["/images/campaign-detail.jpg"]', 95000, NULL, '{"name":"CalWater Foundation","multiplier":2,"remaining":12000}', 72450, 986, 73, '2026-01-20', '2026-04-07', NULL, 31, 28, '["In September 2025, routine water testing at Riverside Elementary showed lead concentrations of 22 parts per billion in three drinking fountains. The EPA action level is 15 ppb. The school shut off those fountains and started distributing bottled water. Five months later, they are still distributing bottled water.","The fountains were not the problem. The problem is the service lines connecting 340 homes and 12 public buildings in the Riverside District to the city main. These galvanized steel pipes were installed in 1968 and are corroding from the inside. The city''s infrastructure replacement plan has the Riverside District scheduled for 2031. That is five years of families drinking water that may contain unsafe lead levels.","We are not waiting until 2031. This campaign funds point-of-use filtration systems for every affected address, plus a community water quality monitoring network that will generate public data until the pipes are replaced.","Each household receives an under-sink reverse osmosis system certified to NSF/ANSI Standard 58, which removes 99% of lead. The systems cost $340 installed, including a five-year filter subscription. For the 12 public buildings, we are installing higher-capacity commercial units at $1,800 each. Total filtration cost: $137,400, of which $42,400 is covered by a grant from the California Water Resources Control Board.","The remaining $95,000 from this campaign covers the gap, plus the monitoring network. We are deploying 28 continuous water quality sensors across the district. These IoT sensors measure lead, copper, pH, and turbidity every 15 minutes and publish results to a public dashboard. Residents can check their block''s water quality on their phone. The sensors cost $890 each and are manufactured by a startup out of MIT called Hydrosense. They have already been deployed in Flint, Michigan and Newark, New Jersey.","I have been studying water quality in this district for three years as part of my research at UC Riverside. My lab published the initial contamination findings that led to the school fountain shutdowns. I know these pipes, I know this water, and I know exactly what filtration technology works for this specific contamination profile.","Four of my five previous campaigns have reached their goals. The one that fell short, the Fish Passage Project, taught me to be more conservative with timelines. The scope was right but the construction season was too short. I have built that lesson into this project: all 340 residential installations can be completed in 12 weeks by a team of four plumbers, and we have contracts signed with two licensed firms.","The monitoring network is just as important as the filters. Right now, residents only learn about water quality problems when someone happens to run a test. Our sensor grid changes that. If lead levels spike on a given block, the dashboard alerts residents within 15 minutes. The data is also shared with the city''s Department of Public Utilities, creating a public record that strengthens the case for accelerating the pipe replacement timeline. Three city council members have already cited our preliminary sensor data in their budget proposals for 2027.","Every family in the Riverside District deserves to turn on their kitchen faucet without wondering what is in the water. The city says 2031. We say now."]', '[{"id":"update-3-1","date":"2026-03-01","title":"First 80 Homes Have Filtration Installed","content":"Both plumbing crews are ahead of schedule. Homeowner satisfaction surveys show 100% approval so far. The under-sink units are nearly invisible and residents report noticeably better water taste.","image":"/images/campaign-detail.jpg"},{"id":"update-3-2","date":"2026-02-15","title":"Monitoring Sensors Deployed","content":"All 28 Hydrosense sensors are live and publishing to our public dashboard. Early data confirms our lab findings: lead levels in the southeast quadrant average 19 ppb, with spikes to 31 ppb after periods of low flow."},{"id":"update-3-3","date":"2026-01-28","title":"Equipment Has Arrived","content":"340 under-sink RO units and 12 commercial filtration systems delivered to our staging warehouse. Filter subscriptions confirmed with the manufacturer through 2031."}]', '[{"donorName":"Alex Rivera","text":"Elena presented her water quality data at our neighborhood meeting. The science is solid and the plan is practical. This is exactly the kind of direct action our district needs.","date":"2026-02-05"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-4', 'profile-4', 'Tech Tutoring Center for Underserved Youth', 'Education', 'active', '/images/hero-education.jpg', '["/images/campaign-detail.jpg"]', 60000, NULL, NULL, 38200, 498, 77, '2026-02-01', '2026-04-15', NULL, 39, 12, '["Last spring, I asked my AP Computer Science class how many of them had a quiet place at home to practice coding. Out of 34 students, nine raised their hands. The rest work on shared family computers in kitchens and living rooms, often after 9 PM when younger siblings are asleep. Two students told me they do most of their homework on their phones.","These are students who passed a competitive entrance exam to get into this course. They have the ability. What they lack is a place to work.","This campaign funds a dedicated tutoring and computer lab space in the Pilsen neighborhood of Chicago''s Lower West Side. We have secured a two-year lease on a 1,200-square-foot storefront at 18th and Ashland, four blocks from Benito Juarez Community Academy. The space will hold 20 workstations, a small meeting area for group projects, and a loaner laptop checkout counter.","The $60,000 covers buildout, equipment, and the first year of operations. Specifically: $18,000 for 20 refurbished workstations sourced through PCs for People, a nonprofit refurbisher. Each machine runs Linux Mint with a full development environment pre-configured. $12,000 for furniture, networking, electrical upgrades, and security. $8,000 for 30 Chromebooks for the loaner program. $22,000 for twelve months of rent, utilities, internet, and a part-time center coordinator.","The center will be open Monday through Saturday, 3 PM to 8 PM on school days and 10 AM to 6 PM on Saturdays. Volunteer tutors from the Illinois Institute of Technology and UIC have already committed to staffing rotations. I will be on site three evenings a week myself.","We are not starting from scratch. The Community WiFi Network campaign I ran last year brought free internet to 380 households in this same neighborhood. The Laptop Drive put 120 refurbished machines into students'' hands. The STEM Library stocked three branch libraries with books, kits, and coding resources. Each of those projects solved one piece of the puzzle. But none of them gave students what they actually need most: a quiet room with a working computer and someone nearby who can help when they get stuck.","The tutoring center fills that gap. We have already mapped the curriculum to align with Chicago Public Schools'' CS pathway, so students can use their time at the center to work on actual class assignments. The volunteer tutors are not just CS majors. We specifically recruited students who grew up in neighborhoods like Pilsen, who understand what it means to learn to code without a desk of your own. That representation matters. When a 14-year-old sees a tutor who looks like them and came from the same blocks, the message is clear: this path is open to you.","If we hit our stretch goal of $75,000, the additional $15,000 funds a summer intensive program: six weeks, 30 students, building real portfolio projects. Last summer I ran a smaller version out of the school library. Four of those students are now interning at local tech companies. Imagine what happens when they have a proper space to work in."]', '[{"id":"update-4-1","date":"2026-03-01","title":"Lease Signed, Buildout Begins","content":"Keys in hand as of yesterday. Electrical upgrades start this week. The storefront has great natural light and the landlord agreed to cover the cost of repainting the exterior."},{"id":"update-4-2","date":"2026-02-15","title":"20 Volunteer Tutors Confirmed","content":"IIT and UIC CS departments have committed 20 volunteer tutors for the spring semester. We have enough coverage for every open hour with two tutors on site."}]', '[{"donorName":"Priya Desai","text":"My daughter used the laptops from Samir''s device drive last year. Having a real workspace to go to after school would change everything for her and her friends.","date":"2026-02-20"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-24', 'profile-1', 'Rebuild the Albina Community Center', 'Community', 'active', '/images/hero-community.jpg', '["/images/campaign-detail.jpg"]', 85000, NULL, NULL, 52000, 683, 76, '2026-01-20', '2026-03-22', NULL, 14, 15, '["The Albina Community Center on NE Martin Luther King Jr. Boulevard closed its doors in November 2025 after a pipe burst in the ceiling above the main hall and flooded three rooms. The building is 62 years old. The insurance covered water extraction and mold remediation, but the adjuster''s report flagged $210,000 in deferred maintenance that the policy does not cover. The Albina Neighborhood Association has $128,000 in reserves. That leaves an $82,000 gap, and without it, the center stays closed.","This is the building where 14 community organizations meet every week. The after-school tutoring program for 85 kids from King Elementary. The senior lunch program that serves 40 meals every Wednesday. The weekend ESL classes that 60 adults attend. The teen basketball league that keeps 120 kids off the street from November through March. All of it has been displaced since the flood.","The $85,000 goal covers three things. First, $38,000 for the HVAC replacement. The existing system is the original 1963 installation. It was limping along before the flood, and the water damage finished it. We are installing a modern heat pump system that will cut the building''s energy costs by 40% and eliminate the gas furnace entirely. The contractor is Eco Comfort PDX, the same company that retrofitted the Eastside Community Kitchen last year.","Second, $27,000 for the electrical panel upgrade and rewiring of the main hall and two meeting rooms. The current wiring is cloth-insulated aluminum from the original construction. It passed inspection in 2019, but the electrician who assessed the flood damage told us it is one bad connection away from a fire. We are replacing it with copper wiring to modern code, adding 20-amp circuits for the kitchen and AV equipment, and installing LED lighting throughout.","Third, $20,000 for the community kitchen renovation. The kitchen serves the senior lunch program, the weekend potlucks, and the cooking classes that the Portland Community College extension program runs here twice a month. The flood did not reach the kitchen directly, but the mold remediation required removing drywall in the adjacent hallway, and the contractor discovered termite damage in the shared wall. We are replacing the wall, adding a commercial exhaust hood that meets county health code, and resurfacing the counters.","I have been on the Albina Neighborhood Association board for four years and managed six campaigns through FundForge. Every one of them delivered on budget and on time. The Cannery rooftop garden, the tool library, the seed vault, the bee sanctuary, the free pantry network, the playground renovation. This community trusts me with their money because I show them exactly where it goes.","The center has been closed for four months. Every week that passes, another program finds a temporary home somewhere else, and the risk is that temporary becomes permanent. The senior lunch program moved to a church basement with no kitchen. The tutoring program is running out of a volunteer''s living room. We need the center back, and we need it back right."]', '[{"id":"update-24-1","date":"2026-03-04","title":"HVAC Contractor Confirmed","content":"Eco Comfort PDX has locked in our installation date for March 24. The heat pump units are in stock at their Portland warehouse. If we close the funding gap this week, work starts the day after the campaign ends."},{"id":"update-24-2","date":"2026-02-18","title":"Electrical Assessment Complete","content":"The rewiring scope is finalized. 14 circuits in the main hall and meeting rooms, plus the kitchen upgrade. The electrician confirmed we can keep the existing conduit runs, which saves about $4,000 on labor."},{"id":"update-24-3","date":"2026-02-01","title":"Insurance Settlement Received","content":"The Albina Neighborhood Association received the final insurance payout of $128,000. Combined with this campaign, we will have full coverage for the repair scope. No additional funding sources needed."}]', '[{"donorName":"Patricia Okafor","text":"My kids have been in the after-school program at the Albina Center for three years. They ask me every week when it''s opening back up. Maya will get this done.","date":"2026-02-22"},{"donorName":"Robert Yamamoto","text":"I attend the Wednesday senior lunch. The church basement is fine, but it''s not home. We need our center back.","date":"2026-03-01"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-25', 'profile-2', 'Eastside Maker Lab: Open-Access Fabrication for All', 'Technology', 'active', '/images/hero-makerlab.jpg', '["/images/campaign-detail.jpg"]', 60000, NULL, NULL, 48000, 600, 80, '2026-01-10', '2026-03-17', NULL, 9, 25, '["The closest maker space to East Austin is a 45-minute bus ride across town. It charges $150 a month for membership. For the independent fabricators, small-batch manufacturers, and student inventors on this side of the highway, that is not access. That is a barrier with a price tag.","We are opening the Eastside Maker Lab in a 2,800-square-foot warehouse at 7th and Chicon, three blocks from the Plaza Saltillo transit stop. The space will house a metal shop, a wood shop, a digital fabrication bay with two large-format 3D printers and a 60-watt laser cutter, an electronics bench, and a classroom area for workshops. Membership will be $40 per month, with a free tier for students and anyone earning below 200% of the federal poverty line.","The $60,000 goal covers buildout and the first eight months of operations. Here is the breakdown. $22,000 for equipment: two Prusa XL 3D printers, an OMTech 60W laser cutter, a SawStop table saw, a drill press, a MIG welder, and hand tools. We are buying the 3D printers and laser new for warranty coverage. The woodworking and metalworking tools are sourced through an industrial surplus dealer in San Marcos at 40% of retail.","Next, $18,000 for the space itself: first and last month''s rent, electrical upgrades to support the metal shop''s 220V circuits, dust collection ducting for the wood shop, ventilation for the laser cutter, and a compressed air system for the spray booth. The landlord is covering the cost of a new roll-up door on the loading dock side, which gives us material handling access.","The remaining $20,000 funds eight months of operations: utilities, insurance, consumables like filament and plywood, a part-time lab manager, and the free membership subsidy. After month eight, the lab needs to sustain itself on membership revenue. At our projected mix of 80 paid members and 30 free-tier users, monthly revenue covers monthly costs with a 12% margin. That is tight, but it matches the financial model of three comparable labs in Dallas, Houston, and San Antonio that are all still operating after 3+ years.","I ran the Makers Space Renovation campaign two years ago, which equipped a community workshop with 3D printers, a laser cutter, and woodworking tools. That space now has 200 weekly users. But it is on the west side of town, and the demand from East Austin has been consistent and unmet. Twelve people on the current Makers Space waitlist live within a mile of the Chicon location.","The fabrication economy is real. Three graduates of our west-side Makers Space now run small businesses: custom furniture, laser-cut signage, and 3D-printed prosthetic adapters. Two of them started with nothing more than an idea and free access to equipment. The Eastside Maker Lab is not a hobby shop. It is small-business infrastructure for a neighborhood that has been asking for it."]', '[{"id":"update-25-1","date":"2026-03-06","title":"Equipment Ordered - Delivery March 18","content":"Both Prusa XL printers and the OMTech laser are ordered and shipping to the warehouse. The surplus dealer in San Marcos has our woodworking and metalworking package reserved. We pick it up Saturday."},{"id":"update-25-2","date":"2026-02-20","title":"Lease Signed, Electrical Work Underway","content":"The warehouse at 7th and Chicon is ours. The electrician started the 220V circuit installations on Monday. Dust collection ducting arrives next week. We are on track for a soft opening in early April."}]', '[{"donorName":"Angela Torres","text":"I''ve been driving to the west-side Makers Space for a year to prototype my product designs. Having a lab in East Austin changes everything for me and at least a dozen other makers I know.","date":"2026-02-25"},{"donorName":"Derek Washington","text":"Jonas built the original Makers Space and it is still running strong two years later. He knows how to set these up to last.","date":"2026-03-02"}]', NULL);
INSERT INTO campaigns (id, organizer_id, title, category, status, hero_image, images, goal, stretch_goal, matching_sponsor, raised, backer_count, average_gift, created_at, ends_at, ended_at, days_left, weekly_momentum, story, updates, testimonials, summary) VALUES ('campaign-26', 'profile-4', 'Pilsen Youth Mural Festival', 'Arts & Culture', 'active', '/images/hero-mural.jpg', '["/images/campaign-detail.jpg"]', 45000, NULL, NULL, 18000, 247, 73, '2026-02-10', '2026-04-05', NULL, 28, 8, '["Pilsen has more public murals per square mile than any neighborhood in Chicago. The tradition goes back to the 1960s, when Mexican-American artists transformed blank walls along 18th Street into declarations of identity, resistance, and pride. Fifty years later, those murals are fading. Nine were demolished in the last three years as buildings sold to developers. The ones that remain are weathered and cracking. And the generation of kids growing up in Pilsen today has never held a spray can or a brush on a scaffold.","The Pilsen Youth Mural Festival is a six-week program that pairs 30 high school students with six professional muralists to design and paint four large-scale public murals across the neighborhood. The students do not just assist. They drive the creative process: researching neighborhood history, sketching concepts, presenting proposals to community review panels, and executing the final works on walls up to 40 feet wide.","The $45,000 budget breaks down as follows. $18,000 for artist stipends: six professional muralists at $3,000 each for six weeks of mentorship, including two Saturdays of wall painting per mural. These are working artists from the Pilsen community. We are not importing talent. All six grew up within 10 blocks of the festival sites. $9,000 for materials: exterior-grade paint, primers, sealants, scaffolding rental, lifts, and safety equipment. We are using Novacolor mineral silicate paint, which resists UV degradation for 25+ years, twice the lifespan of conventional exterior acrylics.","Another $8,000 covers the student program: stipends of $200 per student for the six-week commitment, plus transit cards, meals during Saturday painting days, and printed portfolios of their work. These are not volunteers. They are apprentices learning a trade that has economic value. Three graduates of a similar program in the Bronx now work as professional muralists earning $60,000 to $80,000 a year.","The remaining $10,000 covers logistics, permits, insurance, a closing exhibition at the National Museum of Mexican Art, and a documentary short produced by students from Columbia College Chicago''s film program. The documentary becomes a portfolio piece for the students and a fundraising asset for future cohorts.","I teach computer science, not art. But I have spent three years running campaigns in Pilsen, and the one thing I hear from students, parents, and community leaders is that the neighborhood''s cultural identity is eroding. The WiFi network, the laptops, the tutoring center - those are infrastructure. This festival is about the soul of the neighborhood. The murals on 18th Street taught a generation of kids that their stories mattered enough to put on a wall. This program teaches the next generation to pick up the brush.","The four wall sites are confirmed. The building owners have signed permission agreements. The National Museum of Mexican Art is hosting the exhibition opening. The six muralists are committed. We just need the funding to make it happen this summer."]', '[{"id":"update-26-1","date":"2026-03-05","title":"Student Applications Open","content":"We received 47 applications in the first three days for 30 spots. Benito Juarez Community Academy is promoting the program through their art department. Selection panel meets March 15."},{"id":"update-26-2","date":"2026-02-20","title":"All Four Wall Sites Confirmed","content":"Building owners at 18th and Paulina, 19th and Ashland, Blue Island and Cermak, and Halsted and 18th have signed our permission agreements. Each wall gets a 10-year maintenance commitment from the property owner."}]', '[{"donorName":"Maria Gutierrez","text":"My father painted one of the original 18th Street murals in 1972. Seeing Pilsen''s kids carry that tradition forward means everything to our family.","date":"2026-02-28"},{"donorName":"Kevin O''Brien","text":"Samir''s tech programs have transformed this neighborhood. Now he''s tackling culture. The community center kids are already excited about applying.","date":"2026-03-03"}]', NULL);
